#include &lt;stdio.h&gt;
#include &lt;stdlib.h&gt;

// We pass int ** so we can modify where the caller's pointer looks.
void allocate_buffer(int **buf_ref, size_t size) {
    if (buf_ref == NULL) return;

    // Dereferencing buf_ref accesses the caller's physical pointer variable.
    *buf_ref = malloc(size * sizeof(int));

    if (*buf_ref != NULL) {
        // Double dereference accesses the actual allocated int memory
        **buf_ref = 99; 
    }
}

int main() {
    int *my_buffer = NULL;

    // We pass the Address-Of our pointer
    allocate_buffer(&my_buffer, 100);

    if (my_buffer != NULL) {
        printf("First element: %d\n", my_buffer[0]); // Prints 99
        free(my_buffer);
    }
    return 0;
}

typedef struct Node {
    int data;
    struct Node *next;
} Node;

// Correct approach: Takes a pointer to the head pointer
void push_front(Node **head_ref, int new_data) {
    Node *new_node = malloc(sizeof(Node));
    new_node->data = new_data;

    // The new node points to whatever the head CURRENTLY points to
    new_node->next = *head_ref;

    // We rewrite the head pointer to point to our new node
    *head_ref = new_node;
}

