// char *argv[] is perfectly identical to char **argv
int main(int argc, char *argv[]) {
    // Guard against out-of-bounds array access
    if (argc < 2) {
        printf("Usage: %s [filename]\n", argv[0]);
        return 1;
    }

    // argv[argc] is guaranteed to be NULL by the C standard.
    // This allows traversal without using the 'argc' counter if desired.
    for (int i = 0; argv[i] != NULL; i++) {
        printf("Arg %d: %s\n", i, argv[i]);
    }

    return 0;
}

#include &lt;stdio.h&gt;

void syntax_matters() {
    // 1. Array of 3 pointers (Total 24 bytes). 
    // Used for jagged arrays like string dictionaries.
    char *dictionary[3] = {"Apple", "Banana", "Cat"};
    printf("%c\n", dictionary[1][0]); // Prints 'B'

    // 2. Pointer to an Array of 3 chars (Total 8 bytes).
    // Used to traverse flat 2D matrices.
    char flat_grid[2][3] = {{'A','B','C'}, {'D','E','F'}};
    char (*ptr_to_array)[3] = flat_grid;

    // Advances by 3 bytes (the width of the array it points to)
    ptr_to_array++; 
    printf("%c\n", (*ptr_to_array)[0]); // Prints 'D'
}

