}

#include &lt;stdlib.h&gt;

int **create_matrix(size_t rows, size_t cols) {
    // Step 1: Allocate the routing "Spine" (Array of pointers)
    int **matrix = malloc(rows * sizeof(int *));
    if (!matrix) return NULL;

    // Step 2: Allocate the actual data as ONE contiguous block
    int *data_block = malloc(rows * cols * sizeof(int));
    if (!data_block) {
        free(matrix);
        return NULL;
    }

    // Step 3: Map the spine pointers to exact offsets within the data block
    for (size_t i = 0; i < rows; i++) {
        matrix[i] = data_block + (i * cols);
    }

    return matrix; // Allows matrix[r][c] syntax with perfect cache coherence
}

#include &lt;stdlib.h&gt;

void destroy_matrix(int **matrix, size_t rows) {
    if (matrix == NULL) return;

    // Assume 'matrix' was allocated using the "Elite" 2-step method above
    // Engineer attempts to clean up the memory
    free(matrix);
}
